import { Component, OnInit, OnDestroy } from '@angular/core';
import { Router } from '@angular/router';
import { HttpClient, HttpParams } from '@angular/common/http';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-hr-dashboard',
  template: `
  <div class="dashboard-container">
    <aside class="sidebar">
      <div class="logo-area">
        <div class="logo-icon">E</div>
        <span class="logo-text">EventNest <small>HR</small></span>
      </div>
      <nav class="nav-menu">
        <a class="nav-link active"><i class="icon-dashboard"></i> Overview</a>
        <a class="nav-link" (click)="scrollTo('post-section')">Post Internship</a>
        <a class="nav-link" (click)="scrollTo('internships-section')">Internships</a>
        <a class="nav-link" (click)="scrollTo('candidates-section')">Candidates</a>
      </nav>
      <div class="user-profile">
        <div class="avatar">{{ auth.user?.email?.[0]?.toUpperCase() }}</div>
        <div class="user-info">
          <p class="user-name">HR Admin</p>
          <button (click)="logout()" class="logout-link">Logout</button>
        </div>
      </div>
    </aside>

    <main class="main-content">
      <header class="top-header">
        <h1 class="page-title">Recruitment Dashboard</h1>
        <div class="stats-row">
          <div class="stat-card">
            <span class="stat-val">{{ internships.length }}</span>
            <span class="stat-label">Active Roles</span>
          </div>
          <div class="stat-card">
            <span class="stat-val">{{ applications.length }}</span>
            <span class="stat-label">Total Applicants</span>
          </div>
        </div>
      </header>

      <section id="post-section" class="content-section">
        <div class="glass-card">
          <div class="card-header">
            <h3>Create New Opportunity</h3>
            <p>Fill in the details to post a new internship opening.</p>
          </div>
          <div class="form-grid">
            <div class="input-group">
              <label>Job Title</label>
              <input type="text" [(ngModel)]="title" placeholder="e.g. Backend Developer Intern" />
            </div>
            <div class="input-group">
              <label>Location</label>
              <input type="text" [(ngModel)]="location" placeholder="e.g. Remote / Bangalore" />
            </div>
            <div class="input-group">
              <label>CTC (Annual)</label>
              <input type="text" [(ngModel)]="ctc" placeholder="e.g. 5,00,000" />
            </div>
            <div class="input-group">
              <label>Company</label>
              <input type="text" [(ngModel)]="companyName" placeholder="EventNest" />
            </div>
            <div class="input-group full-width">
              <label>Description</label>
              <textarea [(ngModel)]="description" rows="3"></textarea>
            </div>
            <div class="input-group full-width upload-zone">
              <label>JD Document (PDF)</label>
              <div class="file-input-wrapper">
                <input type="file" (change)="onPdfSelected($event)" (focus)="pausePolling()" (blur)="resumePolling()" />
                <span class="file-custom">{{ pdfFile ? pdfFile.name : 'Choose PDF...' }}</span>
              </div>
            </div>
          </div>
          <div class="card-footer">
            <button class="btn btn-secondary" (click)="handlePdfUpload()">1. Upload PDF</button>
            <button *ngIf="pdfUploaded" class="btn btn-primary" (click)="handlePost()">2. Post Internship</button>
          </div>
        </div>
      </section>

      <section id="candidates-section" class="content-section">
        <div class="section-header">
          <h2>Application Pipeline</h2>
          <div class="badge">Live Updates</div>
        </div>

        <div class="candidate-table-card">
          <table class="modern-table">
            <thead>
              <tr>
                <th>Candidate</th>
                <th>Phase</th>
                <th>Interview Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let app of applications">
                <td>
                  <div class="td-candidate">
                    <span class="c-name">{{app.candidateName}}</span>
                    <span class="c-email">{{app.email}}</span>
                  </div>
                </td>
                <td>
                  <span class="status-pill" [attr.data-status]="app.status">{{ app.status }}</span>
                </td>
                <td>
                  <div class="interview-preview">
                    <small *ngIf="app.l1Date">L1: {{formatDate(app.l1Date)}}</small>
                    <small *ngIf="app.hrDate">HR: {{formatDate(app.hrDate)}}</small>
                    <span *ngIf="!app.l1Date && !app.hrDate" class="text-muted">Not Scheduled</span>
                  </div>
                </td>
                <td>
                  <div class="btn-group">
                    <button class="btn-icon" (click)="selectedCandidate = app" title="View Profile">👁️</button>
                    <button class="btn-icon" (click)="router.navigate(['/hr/onboarding', app.email])" title="Onboarding">📋</button>
                  </div>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </section>
    </main>

    <div class="side-panel-overlay" *ngIf="selectedCandidate" (click)="selectedCandidate = null"></div>
    <div class="side-panel" [class.open]="selectedCandidate">
      <div class="panel-header">
        <h3>Candidate Profile</h3>
        <button class="close-btn" (click)="selectedCandidate = null">&times;</button>
      </div>
      <div class="panel-body" *ngIf="selectedCandidate">
        <div class="profile-header">
           <div class="avatar-large">{{ selectedCandidate.candidateName[0] }}</div>
           <h4>{{ selectedCandidate.candidateName }}</h4>
           <p>{{ selectedCandidate.degree }} | {{ selectedCandidate.college }}</p>
        </div>

        <div class="detail-grid">
           <div class="detail-item"><strong>CGPA</strong> {{selectedCandidate.cgpa}}</div>
           <div class="detail-item"><strong>Skills</strong> {{selectedCandidate.skills}}</div>
        </div>

        <div class="action-zone">
          <a class="btn btn-outline full-width" [href]="'http://localhost:8080/resumes/' + selectedCandidate.resumeFileName" target="_blank">Download Resume</a>
        </div>

        <div class="scheduler-box" *ngIf="showScheduleOptions(selectedCandidate)">
          <h5>Schedule Next Round</h5>
          <input type="date" [ngModel]="getScheduleValue(selectedCandidate.id,'date')" (ngModelChange)="setScheduleValue(selectedCandidate.id,'date',$event)" />
          <select [ngModel]="getScheduleValue(selectedCandidate.id,'mode')" (ngModelChange)="setScheduleValue(selectedCandidate.id,'mode',$event)">
            <option value="ONLINE">Online</option>
            <option value="OFFLINE">Offline</option>
          </select>
          <button class="btn btn-primary full-width" (click)="scheduleInterview(selectedCandidate.id, selectedCandidate.status)">
            Confirm {{ scheduleLabel(selectedCandidate) }}
          </button>
        </div>
      </div>
    </div>
  </div>
  `,
  styles: [`
    :host {
      --primary: #6366f1;
      --primary-dark: #4f46e5;
      --bg-light: #f8fafc;
      --text-main: #1e293b;
      --text-muted: #64748b;
      --white: #ffffff;
      --border: #e2e8f0;
      --radius: 12px;
      --shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
    }

    .dashboard-container {
      display: flex;
      min-height: 100vh;
      background: var(--bg-light);
      font-family: 'Inter', system-ui, sans-serif;
      color: var(--text-main);
    }

    /* Sidebar Styling */
    .sidebar {
      width: 260px;
      background: #0f172a;
      color: white;
      display: flex;
      flex-direction: column;
      position: fixed;
      height: 100vh;
      padding: 24px;
    }

    .logo-area {
      display: flex;
      align-items: center;
      gap: 12px;
      margin-bottom: 40px;
    }

    .logo-icon {
      background: var(--primary);
      width: 35px;
      height: 35px;
      border-radius: 8px;
      display: grid;
      place-items: center;
      font-weight: bold;
    }

    .nav-link {
      display: block;
      padding: 12px;
      color: #94a3b8;
      text-decoration: none;
      border-radius: 8px;
      margin-bottom: 8px;
      cursor: pointer;
      transition: all 0.2s;
    }

    .nav-link:hover, .nav-link.active {
      background: rgba(255,255,255,0.1);
      color: white;
    }

    /* Main Content */
    .main-content {
      margin-left: 260px;
      flex: 1;
      padding: 40px;
    }

    .top-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 32px;
    }

    .stats-row { display: flex; gap: 20px; }
    .stat-card {
      background: white;
      padding: 15px 25px;
      border-radius: var(--radius);
      box-shadow: var(--shadow);
      text-align: center;
    }
    .stat-val { display: block; font-size: 24px; font-weight: 800; color: var(--primary); }
    .stat-label { font-size: 12px; color: var(--text-muted); text-transform: uppercase; }

    /* Glass Cards */
    .glass-card {
      background: var(--white);
      border-radius: var(--radius);
      padding: 24px;
      border: 1px solid var(--border);
      box-shadow: var(--shadow);
      margin-bottom: 32px;
    }

    .form-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 20px;
    }
    .full-width { grid-column: span 2; }

    .input-group label {
      display: block;
      font-size: 13px;
      font-weight: 600;
      margin-bottom: 6px;
      color: var(--text-muted);
    }

    input, textarea, select {
      width: 100%;
      padding: 10px 14px;
      border: 1px solid var(--border);
      border-radius: 8px;
      outline: none;
      transition: border 0.2s;
    }

    input:focus { border-color: var(--primary); }

    /* Modern Table */
    .candidate-table-card {
      background: white;
      border-radius: var(--radius);
      overflow: hidden;
      box-shadow: var(--shadow);
    }

    .modern-table {
      width: 100%;
      border-collapse: collapse;
      text-align: left;
    }

    .modern-table th {
      background: #f1f5f9;
      padding: 16px;
      font-size: 13px;
      color: var(--text-muted);
    }

    .modern-table td {
      padding: 16px;
      border-bottom: 1px solid #f1f5f9;
    }

    .td-candidate .c-name { display: block; font-weight: 600; }
    .td-candidate .c-email { font-size: 12px; color: var(--text-muted); }

    .status-pill {
      padding: 4px 10px;
      border-radius: 20px;
      font-size: 11px;
      font-weight: 700;
      text-transform: uppercase;
    }
    .status-pill[data-status="SELECTED"] { background: #dcfce7; color: #166534; }
    .status-pill[data-status="REJECTED"] { background: #fee2e2; color: #991b1b; }

    /* Buttons */
    .btn {
      padding: 10px 20px;
      border-radius: 8px;
      font-weight: 600;
      cursor: pointer;
      border: none;
      transition: 0.2s;
    }
    .btn-primary { background: var(--primary); color: white; }
    .btn-primary:hover { background: var(--primary-dark); }
    .btn-secondary { background: #f1f5f9; color: var(--text-main); }
    .btn-outline { border: 1px solid var(--border); background: transparent; }

    /* Side Panel */
    .side-panel {
      position: fixed;
      right: -400px;
      top: 0;
      width: 400px;
      height: 100vh;
      background: white;
      z-index: 100;
      transition: 0.3s ease-in-out;
      box-shadow: -10px 0 30px rgba(0,0,0,0.1);
      padding: 30px;
    }
    .side-panel.open { right: 0; }
    .side-panel-overlay {
      position: fixed;
      inset: 0;
      background: rgba(0,0,0,0.3);
      backdrop-filter: blur(2px);
      z-index: 99;
    }
  `]
})
export class HrDashboardComponent implements OnInit, OnDestroy {
  // ... (keep all your existing logic/methods exactly as they are)

  scrollTo(id: string) {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  }

  // Ensure these match your existing logic
  // ... (rest of your component class)
}
